        fs.mkdirSync(srcDir);
        fs.writeFileSync(path.join(srcDir, 'test.txt'), 'test content');

        await ZipAFolder.zip(srcDir, outputFile);

        const stats = fs.statSync(outputFile);
        const fileSize = stats.size;

