        fs.mkdirSync(srcDir);
        fs.writeFileSync(path.join(srcDir, 'test.txt'), testContent);

        await ZipAFolder.zip(srcDir, outputFile);

        const compressedStats = fs.statSync(outputFile);
        const compressedSize = compressedStats.size;

